SELECT h.*, ste.site_nm AS site_nm, ite.prod_nm AS order_item_nm, ord.member_nm AS order_nm, usr.user_nm AS chg_user_nm, cd_ois.code_label AS order_item_status_cd_nm FROM odh_order_item_status_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN od_order_item ite ON ite.order_item_id = h.order_item_id LEFT JOIN od_order ord ON ord.order_id = h.order_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id LEFT JOIN sy_code cd_ois ON cd_ois.code_grp = 'ORDER_ITEM_STATUS' AND cd_ois.code_value = h.order_item_status_cd
ORDER BY h.order_item_status_hist_id ASC ORDER BY h.order_item_status_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

